import { useMemo, useState } from 'react';
import { useModelIndex, useModelStore, useModelUpdate, useModelDelete } from '@rhino-dev/rhino-react';
import type { Blog } from '../types';
import { Icon } from '../components/Icons';
import { useToast } from '../components/Toaster';
import { fmtRelative } from '../lib/format';
import { Loading, StatusPill } from './DashboardPage';

const PER_PAGE = 10;
type Sort = '-id' | 'title' | '-title' | 'published' | '-published' | 'created_at' | '-created_at';

export function BlogsPage() {
  const toast = useToast();
  const [search, setSearch] = useState('');
  const [publishedFilter, setPublishedFilter] = useState('');
  const [sort, setSort] = useState<Sort>('-created_at');
  const [page, setPage] = useState(1);
  const [showNew, setShowNew] = useState(false);
  const [editingBlog, setEditingBlog] = useState<Blog | null>(null);
  const [viewingBlog, setViewingBlog] = useState<Blog | null>(null);

  const filters = useMemo(() => {
    const f: Record<string, any> = {};
    if (publishedFilter === 'true') f.published = true;
    if (publishedFilter === 'false') f.published = false;
    return f;
  }, [publishedFilter]);

  const blogs = useModelIndex<Blog>('blogs', {
    filters,
    search: search || undefined,
    sort,
    page,
    perPage: PER_PAGE,
  });

  const store = useModelStore<Blog>('blogs');
  const update = useModelUpdate<Blog>('blogs');
  const del = useModelDelete<Blog>('blogs');

  const list = blogs.data?.data ?? [];
  const pag = blogs.data?.pagination;

  function onSortClick(field: Exclude<Sort, `-${string}`>) {
    setSort(s => (s === field ? (`-${field}` as Sort) : field));
  }

  return (
    <>
      <div className="page-head">
        <div>
          <h1 className="page-title">Blogs</h1>
          <p className="page-sub">Multi-tenant scope: <span className="mono accent">/api/{"{org}"}/blogs</span></p>
        </div>
        <button className="btn btn-primary" onClick={() => setShowNew(true)}>
          <Icon.plus size={14} /> New blog
        </button>
      </div>

      <div className="toolbar">
        <input
          className="input input-search"
          style={{ flex: 1, maxWidth: 320 }}
          placeholder="Search title / body…"
          value={search}
          onChange={e => { setPage(1); setSearch(e.target.value); }}
        />
        <select
          className="input select"
          value={publishedFilter}
          onChange={e => { setPage(1); setPublishedFilter(e.target.value); }}
        >
          <option value="">All status</option>
          <option value="true">Published</option>
          <option value="false">Draft</option>
        </select>
        <span className="faint" style={{ marginLeft: 'auto', fontSize: 12 }}>
          {blogs.isFetching ? 'fetching…' : `${list.length} of ${pag?.total ?? list.length}`}
        </span>
      </div>

      <div className="card" style={{ overflow: 'visible' }}>
        {blogs.isLoading ? <Loading /> : list.length === 0 ? (
          <div className="empty">
            <h3>No blogs match</h3>
            <p>Try a different filter, or create one.</p>
          </div>
        ) : (
          <table className="table">
            <thead>
              <tr>
                <Th label="Title" field="title" sort={sort} onClick={onSortClick} />
                <Th label="Status" field="published" sort={sort} onClick={onSortClick} />
                <Th label="Created" field="created_at" sort={sort} onClick={onSortClick} />
                <th style={{ width: 100 }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {list.map(b => (
                <tr key={b.id} onClick={() => setViewingBlog(b)}>
                  <td>
                    <span style={{ fontWeight: 600, cursor: 'pointer' }}>{b.title ?? '—'}</span>
                    <div className="faint" style={{ fontSize: 11, marginTop: 2 }}>
                      {b.body ? (b.body.length > 90 ? `${b.body.slice(0, 90)}…` : b.body) : '—'}
                    </div>
                  </td>
                  <td>
                    <StatusPill value={b.published ? 'active' : 'draft'} />
                  </td>
                  <td className="faint">{fmtRelative(b.created_at)}</td>
                  <td>
                    <div className="row gap-2" onClick={e => e.stopPropagation()}>
                      <button
                        className="btn btn-ghost btn-icon"
                        title="Edit blog"
                        onClick={() => setEditingBlog(b)}
                      >
                        <Icon.edit size={14} />
                      </button>
                      <button
                        className="btn btn-ghost btn-icon"
                        title="Delete blog"
                        onClick={async () => {
                          if (!confirm(`Delete blog "${b.title}"?`)) return;
                          try {
                            await del.mutateAsync(b.id);
                            toast(`Deleted "${b.title}"`, 'ok');
                          } catch (err) {
                            toast(`Delete failed: ${(err as any).response?.data?.errors?.base?.[0] || (err as Error).message}`, 'error');
                          }
                        }}
                      >
                        <Icon.trash size={14} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {pag && pag.lastPage > 1 && (
          <div className="pager">
            <div className="pager-info">Page {pag.currentPage} of {pag.lastPage} · {pag.total} total</div>
            <div className="pager-ctrls">
              <button className="btn btn-sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>
                <Icon.arrowL size={12} />
              </button>
              <button className="btn btn-sm" disabled={page >= pag.lastPage} onClick={() => setPage(p => p + 1)}>
                <Icon.arrowR size={12} />
              </button>
            </div>
          </div>
        )}
      </div>

      {showNew && (
        <BlogModal
          title="New blog"
          onClose={() => setShowNew(false)}
          onSave={async data => {
            try {
              const created = await store.mutateAsync(data);
              toast(`Created "${created.title}"`, 'ok');
              setShowNew(false);
            } catch (err) {
              toast(`Create failed: ${(err as any).response?.data?.errors?.base?.[0] || (err as Error).message}`, 'error');
            }
          }}
          busy={store.isPending}
        />
      )}

      {editingBlog && (
        <BlogModal
          title="Edit blog"
          blog={editingBlog}
          onClose={() => setEditingBlog(null)}
          onSave={async data => {
            try {
              await update.mutateAsync({ id: editingBlog.id, data });
              toast(`Updated "${editingBlog.title}"`, 'ok');
              setEditingBlog(null);
            } catch (err) {
              toast(`Update failed: ${(err as any).response?.data?.errors?.base?.[0] || (err as Error).message}`, 'error');
            }
          }}
          busy={update.isPending}
        />
      )}

      {viewingBlog && (
        <div className="modal-backdrop" onClick={() => setViewingBlog(null)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{ maxWidth: 600 }}>
            <div className="modal-head">
              <div className="modal-title">{viewingBlog.title ?? '—'}</div>
              <button className="btn btn-ghost btn-icon" onClick={() => setViewingBlog(null)}>
                <Icon.close />
              </button>
            </div>
            <div className="modal-body" style={{ whiteSpace: 'pre-wrap', padding: '20px 0' }}>
              <div style={{ marginBottom: 12 }}>
                <StatusPill value={viewingBlog.published ? 'active' : 'draft'} />
                <span className="faint" style={{ marginLeft: 8, fontSize: 12 }}>
                  Created {fmtRelative(viewingBlog.created_at)}
                </span>
              </div>
              <p style={{ fontSize: 14, lineHeight: 1.6, color: 'var(--fg)' }}>
                {viewingBlog.body ?? <span className="faint">No content</span>}
              </p>
            </div>
            <div className="modal-foot">
              <button className="btn btn-ghost" onClick={() => setViewingBlog(null)}>Close</button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

function Th(props: { label: string; field: string | null; sort?: string; onClick?: (f: any) => void }) {
  const { label, field, sort, onClick } = props;
  if (!field || !onClick) return <th>{label}</th>;
  const active = sort === field || sort === `-${field}`;
  return (
    <th className={active ? 'sorted' : ''} onClick={() => onClick(field)} style={{ cursor: 'pointer' }}>
      {label}
      <span className="sort-arrow">{active ? (sort === field ? '↑' : '↓') : '↕'}</span>
    </th>
  );
}

interface BlogModalProps {
  title: string;
  blog?: Blog;
  onClose: () => void;
  onSave: (data: Partial<Blog>) => Promise<void>;
  busy: boolean;
}

function BlogModal({ title, blog, onClose, onSave, busy }: BlogModalProps) {
  const [blogTitle, setBlogTitle] = useState(blog?.title ?? '');
  const [body, setBody] = useState(blog?.body ?? '');
  const [published, setPublished] = useState(blog?.published ?? false);

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-head">
          <div className="modal-title">{title}</div>
          <button className="btn btn-ghost btn-icon" onClick={onClose}><Icon.close /></button>
        </div>
        <div className="modal-body">
          <form className="form" onSubmit={e => { e.preventDefault(); onSave({ title: blogTitle, body, published }); }}>
            <div className="field">
              <label>Title</label>
              <input className="input" value={blogTitle} onChange={e => setBlogTitle(e.target.value)} required autoFocus />
            </div>
            <div className="field">
              <label>Body</label>
              <textarea className="input" rows={6} value={body} onChange={e => setBody(e.target.value)} required />
            </div>
            <div className="field" style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
              <input
                type="checkbox"
                id="published"
                checked={published}
                onChange={e => setPublished(e.target.checked)}
                style={{ width: 'auto', margin: 0 }}
              />
              <label htmlFor="published" style={{ margin: 0, cursor: 'pointer' }}>Published</label>
            </div>
            <div className="modal-foot" style={{ padding: 0, border: 0, marginTop: 16 }}>
              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
              <button type="submit" className="btn btn-primary" disabled={busy}>
                {busy ? <span className="spinner" /> : <Icon.check size={14} />} Save
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

